// // This module increments the counter on the rising edge of the clock and resets it to 0 when the reset signal is high.
module down_counter (
    input wire clk,
    input wire rst,
    output reg [3:0] q
);

    always @(posedge clk) begin
        if (rst) begin
            q <= 4'b0000;
        end else begin
            q <= q - 1;
        end
    end

endmodule
